3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_SURCHARGE = 0.1;
5	
6	const BASE_PREMIUMS: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	  moonstone: 25,
13	};
14	
15	type Item = { type: string; cursed?: boolean };
16	type Step = { op: string; items: Item[] };
17	type Scenario = { steps: Step[] };
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const BLOCK_SIZE = 3;
21	const BLOCK_BASE_PREMIUM = 60;
22	
23	const basePremiumForType = (type: string): number => BASE_PREMIUMS[type] ?? 0;
24	
25	const itemBasePremium = (item: Item): number => basePremiumForType(item.type);
26	
27	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
28	
29	const countByType = (items: Item[]): Map<string, number> => {
30	  const counts = new Map<string, number>();
31	  for (const item of items) {
32	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
33	  }
34	  return counts;
35	};
36	
37	const componentGroupPremium = (type: string, count: number): number =>
38	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * basePremiumForType(type);
39	
40	const sumItemBasePremiums = (items: Item[]): number => {
41	  const nonComponents = items.filter((item) => !isComponent(item));
42	  const components = items.filter(isComponent);
43	  const nonComponentsTotal = nonComponents.reduce(
44	    (sum, item) => sum + itemBasePremium(item),
45	    0,
46	  );
47	  const componentsTotal = Array.from(countByType(components)).reduce(
48	    (sum, [type, count]) => sum + componentGroupPremium(type, count),
49	    0,
50	  );
51	  return nonComponentsTotal + componentsTotal;
52	};
53	
54	const itemSurcharge = (item: Item): number =>
55	  item.cursed ? itemBasePremium(item) * 0.5 : 0;
56	
57	const sumItemSurcharges = (items: Item[]): number =>
58	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
59	
60	export function runScenario(scenario: unknown): { results: { premium: number }[] } {
61	  const step = (scenario as Scenario).steps[0];
62	  const itemsBase = sumItemBasePremiums(step.items);
63	  const itemSurcharges = sumItemSurcharges(step.items);
64	  const firstInsurance = itemsBase * FIRST_INSURANCE_SURCHARGE;
65	  const premium = Math.ceil(itemsBase + itemSurcharges + firstInsurance + PROCESSING_FEE);
66	  return { results: [{ premium }] };
67	}
